import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Ensure buffer size is limited to prevent buffer overflow
        int bufferSize = Math.min(input.length(), 10);

        char[] buffer = new char[bufferSize];
        input.substring(0, bufferSize).getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
